 1	import NetworkAttachmentDefinitionModel from '@kubevirt-ui/kubevirt-api/console/models/NetworkAttachmentDefinitionModel';
 2	import VirtualMachineCloneModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineCloneModel';
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { UploadTokenRequestModel } from '@kubevirt-utils/models';
 5	import { isEmpty } from '@kubevirt-utils/utils/utils';
 6	import { useAccessReview, useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 7	
 8	import { ALL_NAMESPACES_SESSION_KEY } from '../constants';
 9	
10	type Key = 'attacheNetworks' | 'clone' | 'uploadImage';
11	
12	export type UsePermissions = () => {
13	  capabilitiesData: { [key in Key]: { allowed: boolean; isLoading: boolean; taskName: string } };
14	  isLoading: boolean;
15	};
16	
17	const usePermissions: UsePermissions = () => {
18	  const { t } = useKubevirtTranslation();
19	  const [activeNamespace] = useActiveNamespace();
20	
21	  const [canReadNads, canReadNadsLoading] = useAccessReview({
22	    group: NetworkAttachmentDefinitionModel.apiGroup,
23	    ...(activeNamespace !== ALL_NAMESPACES_SESSION_KEY && { namespace: activeNamespace }),
24	    resource: NetworkAttachmentDefinitionModel.plural,
25	    verb: 'get',
26	  });
27	
28	  const [canCloneVM, canCloneVMLoading] = useAccessReview({
29	    group: VirtualMachineCloneModel.apiGroup,
30	    ...(activeNamespace !== ALL_NAMESPACES_SESSION_KEY && { namespace: activeNamespace }),
31	    resource: VirtualMachineCloneModel.plural,
32	    verb: 'create',
33	  });
34	
35	  const [canCreateUploadToken, canCreateUploadTokenLoading] = useAccessReview({
36	    group: UploadTokenRequestModel.apiGroup,
37	    ...(activeNamespace !== ALL_NAMESPACES_SESSION_KEY && { namespace: activeNamespace }),
38	    resource: UploadTokenRequestModel.plural,
39	    verb: 'create',
40	  });
41	
42	  const capabilitiesData = {
43	    attacheNetworks: {
44	      allowed: canReadNads,
45	      isLoading: canReadNadsLoading,
46	      taskName: t('Attach VirtualMachine to multiple networks'),
47	    },
48	    clone: {
49	      allowed: canCloneVM,
50	      isLoading: canCloneVMLoading,
51	      taskName: t('Clone a VirtualMachine'),
52	    },
53	    uploadImage: {
54	      allowed: canCreateUploadToken,
55	      isLoading: canCreateUploadTokenLoading,
56	      taskName: t('Upload a base image from local disk'),
57	    },
58	  };
59	
60	  const isLoading = !isEmpty(
61	    Object.values(capabilitiesData)?.filter((task) => task.isLoading === true),
62	  );
63	
64	  return {
65	    capabilitiesData,
66	    isLoading,
67	  };
68	};
69	
70	export default usePermissions;

